SELECT u.*, r.name as role_name, r.description as role_description, d.name as department_name, d.code as department_code FROM user u LEFT JOIN role r ON u.role_id = r.id LEFT JOIN department d ON u.department_id = d.id
(u.username LIKE CONCAT('%', #{keyword}, '%') OR u.real_name LIKE CONCAT('%', #{keyword}, '%') OR u.email LIKE CONCAT('%', #{keyword}, '%') OR r.name LIKE CONCAT('%', #{keyword}, '%') OR r.description LIKE CONCAT('%', #{keyword}, '%') OR d.name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY u.id DESC LIMIT #{limit} OFFSET #{offset}
